import{_ as t,o as r,c as a,ai as e}from"./chunks/framework.DMjte4z8.js";const d=JSON.parse('{"title":"地图属性与基础设置","description":"","frontmatter":{"title":"地图属性与基础设置","category":"getting-started","updated":"2026-04-28T00:00:00.000Z","model":"openai/MiniMax-M2.7-highspeed","quality_score":0.72,"discovered_via":"manual","sources":["https://www.hiveworkshop.com/threads/world-editor-tips.5899/","https://world-editor-tutorials.thehelper.net/","https://www.youtube.com/watch?v=pET27ahjUn4","https://rutube.ru/video/0c5eb83e23caa32c2c99f439fe9a37a4/","https://www.scribd.com/document/273666469/WarCraft-III-Tutorial-I-Map-Making"]},"headers":[],"relativePath":"getting-started/地图属性与基础设置.md","filePath":"getting-started/地图属性与基础设置.md","lastUpdated":1777383225000}'),l={name:"getting-started/地图属性与基础设置.md"};function n(i,o,s,u,g,q){return r(),a("div",null,[...o[0]||(o[0]=[e('<h1 id="地图属性与基础设置" tabindex="-1">地图属性与基础设置 <a class="header-anchor" href="#地图属性与基础设置" aria-label="Permalink to “地图属性与基础设置”">​</a></h1><h2 id="什么是地图属性设置" tabindex="-1">什么是地图属性设置 <a class="header-anchor" href="#什么是地图属性设置" aria-label="Permalink to “什么是地图属性设置”">​</a></h2><p>在本节中，你将学习什么是地图属性设置，以及如何找到它。学完本节后，你就能找到修改地图基本信息的入口，知道在哪里更改你的地图名称、游戏人数上限等基本信息。</p><h3 id="地图属性的作用与重要性" tabindex="-1">地图属性的作用与重要性 <a class="header-anchor" href="#地图属性的作用与重要性" aria-label="Permalink to “地图属性的作用与重要性”">​</a></h3><p>地图属性设置是管理你地图&quot;身份信息&quot;的地方，就像一本书的封面和版权页。它包含了地图的名称、作者、游戏人数、地图难度等基本信息[^1]。虽然这些设置看起来很简单，但它们直接影响玩家进入游戏时看到的第一印象，以及游戏能否正常运行。</p><blockquote><p><strong>💡 新手提示</strong>：很多新手会忽略地图属性设置，直接开始做地形和触发器。但一个完整的地图至少应该设置好地图名称和游戏人数，否则玩家可能会困惑。</p></blockquote><h3 id="在哪里找到地图属性设置" tabindex="-1">在哪里找到地图属性设置 <a class="header-anchor" href="#在哪里找到地图属性设置" aria-label="Permalink to “在哪里找到地图属性设置”">​</a></h3><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><strong>第一步：打开World Editor</strong> — 双击桌面图标或通过魔兽争霸III游戏菜单进入编辑器[^3]</li><li><strong>第二步：点击菜单栏的&quot;场景&quot;</strong> — 在编辑器顶部找到&quot;场景&quot;（Scenario）菜单并点击</li><li><strong>第三步：选择&quot;地图属性&quot;</strong> — 在下拉菜单中找到并点击&quot;地图属性&quot;（Map Properties）选项[^2]</li><li><strong>第四步：确认弹窗内容</strong> — 这时会弹出一个设置窗口，你可以看到地图的基本信息编辑区域</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常找不到&quot;地图属性&quot;选项，因为它不在&quot;文件&quot;菜单里，而是在&quot;场景&quot;菜单下。如果你在&quot;文件&quot;菜单里找了半天没找到，这是正常的，换到&quot;场景&quot;菜单试试。</p></blockquote><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该能看到一个包含地图名称（Map Name）、作者（Author）、建议玩家数量（Recommended Players）等信息的设置窗口。你可以在这里修改你的地图基本信息[^4]。记得每次修改后点击&quot;确定&quot;保存设置。</p><blockquote><p><strong>💡 新手提示</strong>：地图属性设置窗口里还有一个&quot;游戏类别&quot;选项，可以选择你的地图是RPG、TD（塔防）还是其他类型，这有助于玩家快速了解你的地图类型。</p></blockquote><h2 id="基础地图参数配置" tabindex="-1">基础地图参数配置 <a class="header-anchor" href="#基础地图参数配置" aria-label="Permalink to “基础地图参数配置”">​</a></h2><p>这一节你将学习如何设置地图的基本参数，包括选择合适的地图尺寸以及理解地图边界和不可通行区域。完成学习后，你就能创建符合自己游戏需求的地图框架。</p><h3 id="操作步骤-1" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-1" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><p><strong>第一步：打开地图设置面板</strong> — 在World Editor顶部菜单栏中，点击&quot;地图&quot;菜单，然后选择&quot;地图属性&quot;选项[^1]。这会打开一个对话框，你可以在里面修改地图的各种基础参数。</p></li><li><p><strong>第二步：选择地图尺寸</strong> — 在地图属性面板中，找到&quot;游戏宽度&quot;和&quot;游戏高度&quot;选项。这些值决定了地图的大小，通常以&quot;砖块&quot;为单位[^2]。小地图适合快节奏对战，大地图则适合RPG冒险。</p></li><li><p><strong>第三步：理解地图边界</strong> — 地图边界是地图的最外围区域，默认情况下单位无法通过。边界通过特殊的不可通行地形（通常显示为黑色区域）来标记[^5]。</p></li><li><p><strong>第四步：设置不可通行区域</strong> — 你可以使用地形工具中的&quot;地形类型&quot;笔刷，将某些区域设置为深水或悬崖来创建不可通行区域[^5]。单位无法通过这些地形。</p></li><li><p><strong>第五步：预览并测试</strong> — 设置完成后，按F9或点击&quot;测试&quot;按钮进入游戏测试你的地图设置是否生效。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：地图尺寸的选择很重要——更大的地图意味着更丰富的视觉体验，但同时也会增加加载时间并需要更复杂的触发器设计。初学者建议从小地图开始练手。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手在创建边界时忽视了边角区域，导致单位能够&quot;逃出&quot;地图。解决方法是确保使用完整的不可通行地形围住地图四周的每个角落。</p></blockquote><h3 id="小结-1" tabindex="-1">小结 <a class="header-anchor" href="#小结-1" aria-label="Permalink to “小结”">​</a></h3><p>完成这些步骤后，你就掌握了地图参数配置的核心要素，能够创建出尺寸合适且具有明确边界的地图框架。在这个框架内，你可以继续添加地形、单位和游戏机制。</p><h2 id="玩家与队伍设置" tabindex="-1">玩家与队伍设置 <a class="header-anchor" href="#玩家与队伍设置" aria-label="Permalink to “玩家与队伍设置”">​</a></h2><p>本节我们将学习如何在地图中配置玩家数量、设置每个玩家的种族（阵营），以及创建和管理队伍（Force）。学完本节后，你将能够为你的RPG地图设置好多人对战的基础框架，让不同玩家操控不同的单位或角色。</p><h3 id="操作步骤-2" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-2" aria-label="Permalink to “操作步骤”">​</a></h3><h4 id="第一步-打开场景参数设置面板" tabindex="-1">第一步：打开场景参数设置面板 <a class="header-anchor" href="#第一步-打开场景参数设置面板" aria-label="Permalink to “第一步：打开场景参数设置面板”">​</a></h4><ol><li>在World Editor（世界编辑器）界面中，点击顶部菜单栏的 <strong>&quot;场景&quot;</strong> 选项[^1]</li><li>在下拉菜单中选择 <strong>&quot;场景参数&quot;</strong>（或者使用快捷键 F4）</li><li>这时会弹出一个窗口，显示所有与地图基本设置相关的内容</li></ol><blockquote><p><strong>💡 新手提示</strong>：第一次打开可能会觉得选项很多，别担心，我们只需要关注&quot;玩家&quot;和&quot;队伍&quot;相关的选项，其他可以先保持默认设置。</p></blockquote><h4 id="第二步-配置玩家槽位" tabindex="-1">第二步：配置玩家槽位 <a class="header-anchor" href="#第二步-配置玩家槽位" aria-label="Permalink to “第二步：配置玩家槽位”">​</a></h4><ol><li>在场景参数窗口中，找到 <strong>&quot;玩家&quot;</strong> 选项卡（通常在左侧标签页中）[^2]</li><li>你会看到 1-12 共12个玩家槽位，每个槽位代表一个可能的玩家位置</li><li>点击任意槽位，右侧会显示该玩家的详细设置： <ul><li><strong>玩家名称</strong>：可以自定义显示的名字，如&quot;玩家1&quot;、&quot;红方&quot;等</li><li><strong>所属阵营/种族</strong>：从下拉菜单中选择 Hum（人类）、Orc（兽族）、Undead（亡灵）、Night Elf（暗夜精灵）等[^1]</li><li><strong>队伍颜色</strong>：设置该玩家在地图上显示的颜色（红色、蓝色、绿色等）</li><li><strong>游戏开始资源</strong>：设置玩家初始的金钱和木材数量</li></ul></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常把所有玩家槽位都设置为&quot;可使用&quot;，导致即使只有1个人想玩也需要选择所有种族。正确做法是：如果是单人RPG地图，只保留1-2个槽位为&quot;可使用&quot;，其他设为&quot;关闭&quot;或&quot;不使用&quot;。</p></blockquote><h4 id="第三步-创建队伍-force" tabindex="-1">第三步：创建队伍（Force） <a class="header-anchor" href="#第三步-创建队伍-force" aria-label="Permalink to “第三步：创建队伍（Force）”">​</a></h4><p>队伍（Force）是Warcraft III中用于管理玩家分组的重要概念。比如你的RPG地图有&quot;联盟&quot;和&quot;部落&quot;两个阵营，就需要创建两个Force。</p><ol><li>在场景参数窗口中，点击 <strong>&quot;部队&quot;</strong> 选项卡（或称为&quot;Force&quot;选项卡）[^1]</li><li>点击 <strong>&quot;新建部队&quot;</strong> 按钮，创建一个新的队伍</li><li>为队伍起一个名字，比如&quot;联盟部队&quot;或&quot;部落部队&quot;</li><li>在右侧的 <strong>&quot;玩家列表&quot;</strong> 中，勾选属于该队伍的玩家槽位</li></ol><blockquote><p><strong>💡 新手提示</strong>：一个玩家可以同时属于多个队伍。比如设计一个&quot;所有人vs电脑&quot;的地图，可以让所有玩家同时属于&quot;玩家联盟&quot;这个队伍，然后设置敌对关系时就能一键设置。</p></blockquote><h4 id="第四步-设置队伍之间的关系" tabindex="-1">第四步：设置队伍之间的关系 <a class="header-anchor" href="#第四步-设置队伍之间的关系" aria-label="Permalink to “第四步：设置队伍之间的关系”">​</a></h4><ol><li>在&quot;部队&quot;选项卡中，选中一个队伍</li><li>点击 <strong>&quot;联盟设置&quot;</strong> 或类似按钮</li><li>在弹出的对话框中，选择该队伍与其他队伍或玩家的关系： <ul><li><strong>联盟（Ally）</strong>：结盟关系，可以互相看见、互相治疗</li><li><strong>共享视野（Shared Vision）</strong>：能看到对方的视野但不能治疗</li><li><strong>可控制（Control）</strong>：可以控制对方的单位</li><li><strong>共享单位控制（Shared Unit Control）</strong>：可以同时控制同一个单位</li></ul></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手设置了联盟但没有正确设置&quot;共享视野&quot;，结果队友看不到地图上敌人位置。一定要记得检查所有联盟设置是否完整！</p></blockquote><h3 id="小结-2" tabindex="-1">小结 <a class="header-anchor" href="#小结-2" aria-label="Permalink to “小结”">​</a></h3><p>完成以上四个步骤后，你应该已经成功为地图配置好了玩家槽位和队伍设置。你可以点击编辑器顶部的 <strong>&quot;测试地图&quot;</strong> 按钮（绿色三角▶️图标）来启动游戏，验证玩家设置是否生效[^3]。在测试时，你可以通过按住ALT键再按F4来快速退出测试返回编辑器。</p><p>记得保存你的地图！使用 <strong>Ctrl + S</strong> 快捷键保存是个好习惯，可以避免辛苦做的东西丢失。</p><h2 id="游戏模式与难度设置" tabindex="-1">游戏模式与难度设置 <a class="header-anchor" href="#游戏模式与难度设置" aria-label="Permalink to “游戏模式与难度设置”">​</a></h2><p>本节将教你如何在地图编辑器中设置游戏模式和难度选项。学完本节后，你将能够为你的RPG地图选择合适的地图类型，并配置难度等级和游戏速度，让玩家进入游戏时能获得正确的体验。</p><h3 id="操作步骤-3" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-3" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><p><strong>打开场景参数面板</strong> — 在World Editor（世界编辑器）顶部的菜单栏中，点击&quot;场景&quot;菜单，然后选择&quot;场景参数&quot;选项[^1]。这是一个非常重要的面板，你的地图所有核心设置都在这里。</p></li><li><p><strong>选择地图类型</strong> — 在&quot;场景参数&quot;面板中，找到&quot;地图类型&quot;选项区域。你会看到三个主要选项：</p><ul><li><strong>自定义地图</strong> — 这是RPG地图最常用的类型，适合故事驱动的游戏[^2]</li><li><strong>对战地图</strong> — 适合即时战略类PvP游戏</li><li><strong>战役地图</strong> — 魔兽争霸官方战役使用，特殊功能较多</li></ul><p>作为RPG地图创作者，你几乎总是选择&quot;自定义地图&quot;。</p></li><li><p><strong>设置难度等级</strong> — 在同一面板中找到&quot;难度&quot;下拉菜单。选项通常包括：简单、普通、困难、噩梦、疯狂。每个难度等级会影响什么？</p><blockquote><p><strong>💡 新手提示</strong>：难度等级本身不会自动改变游戏内容！你需要在触发器或游戏数据中编写逻辑，根据玩家选择的难度来调整敌人血量、伤害或奖励。建议在游戏开始时显示玩家选择的难度，并在整个游戏中应用相应的数值。</p></blockquote></li><li><p><strong>配置游戏速度</strong> — 在&quot;游戏选项&quot;区域找到&quot;游戏速度&quot;设置[^3]。可选速度包括：缓慢、正常、快速、较快、最快。RPG地图通常建议使用&quot;正常&quot;或&quot;快速&quot;，因为RPG玩家需要更多时间探索和做任务，不需要像对战那样的高节奏操作。</p></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手误以为设置了&quot;困难&quot;难度后，敌人会自动变强。实际上，难度选项只是一个记录玩家选择的变量，你需要通过触发器或数据模块手动实现难度效果。否则无论选什么难度，游戏内容都是一模一样的。</p></blockquote><h3 id="小结-3" tabindex="-1">小结 <a class="header-anchor" href="#小结-3" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你的地图已经具备了基本的游戏模式和难度框架。玩家在启动地图时会看到难度选择界面，并能以你设定的游戏速度开始游玩。记住，<strong>难度和速度只是基础设置</strong>，真正的游戏平衡需要你在后续的内容创作中，通过敌人属性、装备数值和触发逻辑来实现。</p><h2 id="地图外观与音效基础" tabindex="-1">地图外观与音效基础 <a class="header-anchor" href="#地图外观与音效基础" aria-label="Permalink to “地图外观与音效基础”">​</a></h2><p>本节将教你设置地图的名称、描述、加载画面和背景音乐。学完本节后，你的地图在玩家点击&quot;开始游戏&quot;时就会展示自定义的名称和背景音乐，给玩家留下专业的第一印象。</p><h3 id="地图名称与描述" tabindex="-1">地图名称与描述 <a class="header-anchor" href="#地图名称与描述" aria-label="Permalink to “地图名称与描述”">​</a></h3><p>地图名称和描述是玩家进入地图前最先看到的信息，一个好的名称和描述能让玩家对你的地图产生兴趣。</p><ol><li><strong>第一步：打开场景管理器</strong> — 在World Editor顶部菜单栏点击&quot;场景&quot;菜单，然后选择最下方的&quot;场景管理器&quot;[^1]</li><li><strong>第二步：找到名称和描述字段</strong> — 在弹出的&quot;场景管理器&quot;对话框中，你会看到&quot;地图名称&quot;和&quot;地图描述&quot;两个输入框[^2]</li><li><strong>第三步：填写内容</strong> — 在&quot;地图名称&quot;中输入你的地图名称，在&quot;地图描述&quot;中写一段简短的介绍（建议50字以内）[^3]</li><li><strong>第四步：保存设置</strong> — 点击&quot;确定&quot;按钮保存</li></ol><blockquote><p><strong>💡 新手提示</strong>：地图名称最好简洁明了，让玩家一眼就知道你的地图是做什么的。描述中可以提到地图类型（如RPG、对战、塔防等）。</p></blockquote><h3 id="加载画面与背景音乐" tabindex="-1">加载画面与背景音乐 <a class="header-anchor" href="#加载画面与背景音乐" aria-label="Permalink to “加载画面与背景音乐”">​</a></h3><p>加载画面是玩家等待进入地图时看到的图片，背景音乐则能在等待时播放音乐，两者配合能让你的地图显得更专业。</p><ol><li><strong>第一步：打开场景管理器</strong> — 同样点击&quot;场景&quot;→&quot;场景管理器&quot;[^1]</li><li><strong>第二步：进入加载画面设置</strong> — 在场景管理器中点击&quot;加载画面&quot;标签页</li><li><strong>第三步：启用自定义加载画面</strong> — 勾选&quot;使用自定义文件&quot;选项[^3]</li><li><strong>第四步：设置背景音乐</strong> — 点击&quot;浏览&quot;按钮选择你的音乐文件（支持.mp3或.wav格式）[^2]</li><li><strong>第五步：设置加载图片</strong> — 同样点击&quot;浏览&quot;按钮选择一张图片作为加载画面背景（推荐尺寸256×256像素）[^4]</li><li><strong>第六步：保存并测试</strong> — 点击&quot;确定&quot;，然后按F6测试地图，检查音乐和画面是否正常显示</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常忘记添加背景音乐，只设置了图片。这是因为音乐文件和图片是分开的两个&quot;浏览&quot;按钮，一定要确保两个都设置了。</p></blockquote><blockquote><p><strong>💡 新手提示</strong>：加载画面的图片不要太大，否则会导致加载时间过长，影响玩家体验。建议图片文件大小控制在1MB以内。</p></blockquote><h3 id="小结-4" tabindex="-1">小结 <a class="header-anchor" href="#小结-4" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你的地图应该已经配置好了名称、描述、加载画面和背景音乐。建议先运行测试（按F6），检查这些内容是否正确显示。现在你已经有了一个外观专业的地图，接下来可以继续学习地形编辑等内容[^5]。</p><h2 id="保存与测试地图" tabindex="-1">保存与测试地图 <a class="header-anchor" href="#保存与测试地图" aria-label="Permalink to “保存与测试地图”">​</a></h2><p>在本节中，你将学会<strong>如何正确保存你创建的地图</strong>，以及<strong>如何在 Warcraft III 游戏中加载并测试它</strong>。学完本节后，你将能够看到自己的地图实际运行起来——这可是做 RPG 地图最有成就感的时刻之一！</p><h3 id="正确的地图保存方法" tabindex="-1">正确的地图保存方法 <a class="header-anchor" href="#正确的地图保存方法" aria-label="Permalink to “正确的地图保存方法”">​</a></h3><ol><li><strong>第一步：点击菜单保存</strong> — 在 World Editor 界面顶部找到菜单栏，点击 <strong>「文件(File)」</strong>，在下拉列表中选择 <strong>「保存地图(Save Map)」</strong>[^1]</li><li><strong>第二步：选择保存位置</strong> — 如果你是第一次保存，会弹出文件浏览器窗口，浏览到你常用的文件夹，建议创建一个专门的「地图项目」文件夹，方便以后管理和修改[^2]</li><li><strong>第三步：命名地图</strong> — 在文件名输入框中给你的地图起一个有意义的名字，比如「口袋妖怪冒险 v1」，<strong>不要使用中文或特殊符号</strong>，使用英文和数字组合最安全，避免加载时出现乱码[^3]</li><li><strong>第四步：确认保存</strong> — 点击「保存」按钮后，如果编辑器底部状态栏显示「地图已成功保存」，就说明一切正常了[^1]</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手保存后找不到文件在哪里！解决方法：保存时注意看地址栏显示的路径，用 <code>Ctrl+D</code> 快速打开文件所在文件夹，确认文件确实存在。</p></blockquote><blockquote><p><strong>💡 新手提示</strong>：养成<strong>每隔10-15分钟按一次 Ctrl+S</strong> 快速保存的好习惯。World Editor 有时会意外崩溃，没有及时保存的工作可能全部丢失！</p></blockquote><h3 id="在游戏中测试地图" tabindex="-1">在游戏中测试地图 <a class="header-anchor" href="#在游戏中测试地图" aria-label="Permalink to “在游戏中测试地图”">​</a></h3><ol><li><strong>第一步：打开测试菜单</strong> — 确保地图已保存后，点击编辑器顶部的 <strong>「场景(Scenario)」</strong> 菜单，选择 <strong>「测试地图(Test Map)」</strong>，或者直接按键盘上的 <strong>F10</strong> 快捷键[^3]</li><li><strong>第二步：等待游戏启动</strong> — 点击后，World Editor 会最小化，Warcraft III 会自动启动并加载你的地图，这个过程大约需要 5-10 秒，请耐心等待[^4]</li><li><strong>第三步：进入测试场景</strong> — 游戏加载后，默认会从地图的<strong>起点区域</strong>开始。你可以用鼠标控制镜头，用 <code>WASD</code> 键移动视野，按住鼠标右键拖拽也可以旋转视角[^5]</li><li><strong>第四步：检查并退出测试</strong> — 在测试过程中，留意地图的地形、单位和任何你设置的初始内容是否符合预期。测试完毕后，直接按 <strong>「ESC」</strong> 键，选择 <strong>「退出游戏」</strong> 即可返回编辑器[^3]</li><li><strong>第五步：修改后重新测试</strong> — 如果测试中发现问题，回到编辑器修改，然后<strong>必须重新保存</strong>，再按 F10 重新进入测试。每次修改后都要记得先保存再测试！[^1]</li></ol><blockquote><p><strong>💡 新手提示</strong>：第一次测试时，建议先不要放置太多单位或复杂的触发器。先从最简单的地形和几个单位开始测试，确认基础功能正常后，再逐步添加内容。这样更容易定位问题来源。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常在编辑器中修改了内容，但没有保存就直接按 F10 测试，结果发现游戏里的内容没有任何变化！<strong>记住：修改 → 保存 → 测试</strong>，这个顺序不能乱。</p></blockquote><h3 id="小结-5" tabindex="-1">小结 <a class="header-anchor" href="#小结-5" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该已经成功<strong>保存了你的第一张地图</strong>，并在 <strong>Warcraft III 中看到它的实际运行效果</strong>。现在你已经掌握了地图开发最核心的「编写-保存-测试」循环，这是所有 RPG 地图开发的基础流程。接下来，你可以继续完善地形、添加更多内容，一步步将你的创意变成完整的游戏！</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://www.hiveworkshop.com/threads/world-editor-tips.5899/" target="_blank" rel="noreferrer">World Editor Tips - HIVE</a> — accessed 2026-04-28 [^2]: <a href="https://world-editor-tutorials.thehelper.net/" target="_blank" rel="noreferrer">Warcraft III World Editor, Warcraft III Map Making Tutorials</a> — accessed 2026-04-28 [^3]: <a href="https://www.youtube.com/watch?v=pET27ahjUn4" target="_blank" rel="noreferrer">Warcraft 3 World Editor - Getting Started! Step-by-Step Tutorial</a> — accessed 2026-04-28 [^4]: <a href="https://rutube.ru/video/0c5eb83e23caa32c2c99f439fe9a37a4/" target="_blank" rel="noreferrer">Warcraft 3 world editor tutorial 1. The basics - Rutube</a> — accessed 2026-04-28 [^5]: <a href="https://www.scribd.com/document/273666469/WarCraft-III-Tutorial-I-Map-Making" target="_blank" rel="noreferrer">WarCraft III Terrain Editor Guide</a> — accessed 2026-04-28</p>',74)])])}const c=t(l,[["render",n]]);export{d as __pageData,c as default};
